const result = $input.first().json;
const runId = result.run_id;
const lastHwm = result.last_hwm;

// Calculate cutoff: use high water mark or fallback to 2 hours ago
const fallbackHours = 2;
let cutoff;
if (lastHwm) {
  cutoff = lastHwm;
} else {
  const d = new Date();
  d.setHours(d.getHours() - fallbackHours);
  cutoff = d.toISOString();
}

console.log('Run ID:', runId);
console.log('Last HWM:', lastHwm);
console.log('Using cutoff:', cutoff);

return [{ json: { run_id: runId, cutoff: cutoff, start_time: new Date().toISOString() } }];

const prepData = $('Prepare Reconciliation').first().json;
const paperlessResponse = $('Fetch All Paperless Documents').first().json;
const qdrantResponse = $('Fetch All Qdrant Documents').first().json;

// Extract Paperless document IDs
const paperlessDocs = (paperlessResponse.results || []).map(d => ({
  id: String(d.id),
  title: d.title,
  modified: d.modified
}));
const paperlessIds = new Set(paperlessDocs.map(d => d.id));

// Extract unique document IDs from Qdrant
const qdrantPoints = qdrantResponse.result?.points || [];
const qdrantDocIds = new Set();
qdrantPoints.forEach(p => {
  if (p.payload?.document_id) {
    qdrantDocIds.add(String(p.payload.document_id));
  }
});

console.log('Paperless docs:', paperlessIds.size);
console.log('Qdrant doc IDs:', qdrantDocIds.size);

// Find orphans (in Qdrant but not in Paperless)
const orphans = [];
qdrantDocIds.forEach(id => {
  if (!paperlessIds.has(id)) {
    orphans.push({ document_id: id, action: 'delete' });
  }
});

// Find missing (in Paperless but not in Qdrant)
const missing = [];
paperlessDocs.forEach(doc => {
  if (!qdrantDocIds.has(doc.id)) {
    missing.push({ document_id: doc.id, title: doc.title, action: 'ingest' });
  }
});

console.log('Orphans to delete:', orphans.length);
console.log('Missing to ingest:', missing.length);

return [{ json: {
  run_id: prepData.run_id,
  start_time: prepData.start_time,
  paperless_count: paperlessIds.size,
  qdrant_count: qdrantDocIds.size,
  orphans: orphans,
  missing: missing
}}];
